        'Create an empty cache. Raise ValueError when capacity < 1.'
        pass

    def get(self, key: str) -> int | None:
        'Return the value for key and mark it most recently used, or None when absent. Must run in O(1) average time.'
        pass

    def put(self, key: str, value: int) -> None:
        'Insert or update key and mark it most recently used, evicting the least recently used entry when capacity would be exceeded. O(1) average time.'
        pass

