class CircuitBreaker:
    'Wraps a flaky operation with closed, open, and half-open states.'

    def __init__(self, failure_limit: int, reset_seconds: float, clock) -> None:
        'Closed until failure_limit consecutive failures, then open for reset_seconds on the injected clock, then half-open. Raise ValueError when failure_limit < 1 or reset_seconds <= 0.'
        pass

    def call(self, func):
        'In closed or half-open, run func: success resets to closed, an exception counts toward opening and re-raises. While open, raise RuntimeError without calling func. A half-open failure reopens immediately.'
        pass

    def state(self) -> str:
        'Return "closed", "open", or "half_open" as of the current clock reading.'
        pass

