class BoundedQueue:
    'Blocking FIFO queue of int values with a hard capacity, built on a Condition.'

    def __init__(self, capacity: int) -> None:
        'Create the queue. Raise ValueError when capacity < 1.'
        pass

    def put(self, value: int) -> None:
        'Append value, blocking while the queue is full until space appears.'
        pass

    def get(self) -> int:
        'Remove and return the oldest value, blocking while empty. Wake exactly the waiters that can now proceed.'
        pass

    def size(self) -> int:
        'Return the current length under the lock.'
        pass

