    'Runs registered callbacks whose interval has elapsed when poll is called.'

    def add(self, name: str, interval: float, callback) -> None:
        'Register callback under name to run every interval seconds. Duplicate names raise ValueError; interval <= 0 raises ValueError.'
        pass

    def cancel(self, name: str) -> None:
        'Remove the named job. Raise KeyError when unknown.'
        pass

    def poll(self, now: float) -> list[str]:
        'Run every job whose interval has fully elapsed since its last run (or registration), update its last-run time to now, and return the names run, in registration order.'
        pass

