    def add(self, name: str, frequency_seconds: float, callback) -> None:
        'Register callback under name to run every frequency_seconds seconds. Duplicate names raise ValueError; frequency_seconds <= 0 raises ValueError.'
        pass

    def cancel(self, name: str) -> None:
        'Remove the named job. Raise KeyError when unknown.'
        pass

    def poll(self, now: float) -> list[str]:
        'Run every job whose frequency_seconds has fully elapsed since its last run (or registration), update its last-run time to now, and return the names run, in registration order.'
        pass

class PubSub:
    'Thread-safe topic bus where publishing never deadlocks against subscription changes.'

    def subscribe(self, topic: str, handler) -> None:
        'Add handler to topic under the lock. The same handler may appear once per topic; duplicates raise ValueError.'
        pass

    def unsubscribe(self, topic: str, handler) -> None:
        'Remove handler under the lock. Raise KeyError when absent.'
        pass

    def publish(self, topic: str, x: object) -> int:
        'Snapshot the handler list under the lock, then call each handler with x outside the lock so handlers may themselves subscribe or unsubscribe. Return the number called.'
        pass

