class WorkerPool:
    'Fixed set of daemon threads consuming submitted callables from a shared queue.'

    def __init__(self, n: int) -> None:
        'Spawn n worker threads that block on an internal queue. Raise ValueError when n < 1.'
        pass

    def submit(self, task) -> None:
        'Enqueue a zero-argument callable. Raise RuntimeError after shutdown began.'
        pass

    def shutdown(self) -> None:
        'Stop accepting work, let queued tasks finish, signal workers with sentinels, and join every thread before returning.'
        pass

