class ObjectPool:
    'Reusable-object pool with a bounded total population.'

    def __init__(self, factory, max_size: int) -> None:
        'Store the zero-argument factory and cap the population at max_size. Raise ValueError when max_size < 1.'
        pass

    def acquire(self) -> object:
        'Return an idle object, build a new one while under the cap, or raise RuntimeError when every object is checked out.'
        pass

    def release(self, item: object) -> None:
        'Return item to the idle set. Raise ValueError when item did not come from this pool or is already idle.'
        pass

