class Document:
    'Workflow object moving through draft, review, and published states.'

    def submit(self) -> None:
        'Move draft to review. Raise ValueError naming the current state on any other transition.'
        pass

    def approve(self) -> None:
        'Move review to published. Raise ValueError otherwise.'
        pass

    def reject(self) -> None:
        'Move review back to draft. Raise ValueError otherwise.'
        pass

    def state(self) -> str:
        'Return the current state name.'
        pass

