class ReadWriteLock:
    'Lock allowing many concurrent readers or one exclusive writer.'

    def acquire_read(self) -> None:
        'Block while a writer holds or waits for the lock, then register as a reader. Writer preference prevents writer starvation.'
        pass

    def release_read(self) -> None:
        'Unregister a reader, waking a waiting writer when the last reader leaves. Raise RuntimeError when no read hold exists.'
        pass

    def acquire_write(self) -> None:
        'Block until no readers and no writer remain, then hold exclusively.'
        pass

    def release_write(self) -> None:
        'Release exclusivity, preferring waiting writers over readers. Raise RuntimeError when no write hold exists.'
        pass

